!function(){"use strict";const e=document.getElementById("contactForm");e&&e.addEventListener("submit",async function(t){t.preventDefault();const n=e.querySelector('button[type="submit"]'),i=n.textContent;n.textContent="Sending...",n.disabled=!0;const o={name:e.querySelector("#name").value.trim(),email:e.querySelector("#email").value.trim(),subject:e.querySelector("#subject").value,message:e.querySelector("#message").value.trim(),created_at:(new Date).toISOString()};try{window.sfi?.db?.insert&&await sfi.db.insert("contact_messages",o),e.innerHTML=`\n            <div style="text-align:center;padding:40px 0">\n                <div style="font-size:3rem;margin-bottom:16px">✅</div>\n                <h2>Message Sent!</h2>\n                <p style="color:var(--color-text-secondary);margin-top:8px">\n                    Thanks ${o.name}, we'll get back to you within 24 hours.\n                </p>\n            </div>`}catch(e){n.textContent=i,n.disabled=!1,"function"==typeof showNotification&&showNotification("Failed to send. Please try again.","error")}})}();